const i = items[0].json;
if (!i.url || !i.method) throw new Error('url and method required');
return [{
  json: {
    url: i.url,
    method: String(i.method).toUpperCase(),
    headers: i.headers || {},
    body: i.body != null ? i.body : null,
    max_retries: Number(i.max_retries != null ? i.max_retries : 3),
    attempt: Number(i.attempt || 0),
    base_wait_ms: Number(i.base_wait_ms || 2000),
    meta: i.meta || {}
  }
}];

const req = $('Normalize Request').item.json;
const resp = items[0].json;
const statusCode = resp.statusCode || resp.status || 0;
const body = resp.body !== undefined ? resp.body : resp;
const retryable = statusCode === 429 || statusCode >= 500;
const attempt = req.attempt;
const canRetry = retryable && attempt < req.max_retries;

if (canRetry) {
  const waitMs = req.base_wait_ms * Math.pow(2, attempt);
  return [{
    json: {
      ok: false,
      should_retry: true,
      wait_ms: waitMs,
      attempt: attempt + 1,
      max_retries: req.max_retries,
      statusCode,
      url: req.url,
      method: req.method,
      headers: req.headers,
      body: req.body,
      base_wait_ms: req.base_wait_ms,
      meta: req.meta,
      error: statusCode === 429 ? 'rate_limited' : `http_${statusCode}`
    }
  }];
}

if (statusCode >= 400 || statusCode === 0) {
  return [{
    json: {
      ok: false,
      should_retry: false,
      statusCode,
      body,
      error: body?.message || body?.error || `HTTP ${statusCode}`,
      meta: req.meta
    }
  }];
}

return [{
  json: {
    ok: true,
    should_retry: false,
    statusCode,
    body,
    meta: req.meta
  }
}];

// Loop retry by returning same shape as Normalize Request output
const j = items[0].json;
return [{
  json: {
    url: j.url,
    method: j.method,
    headers: j.headers,
    body: j.body,
    max_retries: j.max_retries,
    attempt: j.attempt,
    base_wait_ms: j.base_wait_ms,
    meta: j.meta
  }
}];
